import request from '@/utils/request';
// 登录
export const login = (data) => {
    return request({
        url: '/auth/login',
        method: 'post',
        data
    }).then(data => data);
};
// 登出
export const logout = () => {
    return request({
        url: '/auth/logout',
        method: 'post'
    }).then(data => data);
};
// 获取当前用户信息
export const getCurrentUser = () => {
    return request({
        url: '/auth/info',
        method: 'get'
    }).then(data => data);
};
